import{_ as s,W as t,X as o,$ as n,a0 as e,Z as i,Y as l,a1 as c,D as r}from"./framework-f38b131a.js";const p={},d=n("h1",{id:"简介",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#简介","aria-hidden":"true"},"#"),e(" 简介")],-1),u=n("p",null,"拼音输入法应该是年轻人用的最多的输入法了，使用简单方便，依托各大输入法强大的词库联想功能，大大提高了打字效率。但是为了追求极致的打字速度，很多人还会纠结使用9键还是26键快，各执一词谁也说服不了谁。但其实大家用的拼音输入法基本都是全拼输入法，在不借助联想功能的情况下需要完整敲击拼音的每个字母才能录入文字，事实上还有另一种拼音输入法以减少击键次数来达到提升打字速度的目的，也是我们今天的主角——双拼输入法。",-1),g=n("figure",null,[n("img",{src:"https://blog.kevin2li.top/static/img/b178bdd410413eb88664238e11750a15.image.png",alt:"image.png",tabindex:"0",loading:"lazy"}),n("figcaption",null,"image.png")],-1),h=n("p",null,"双拼输入法是使用两个字母对汉字进行编码的方案，第一个字母表示声母，第二字母表示韵母，也就是说任何一个汉字使用两次敲击就可以打出，相比全拼在按键次数上有明显优势，并且上手难度也比五笔输入法小得多，熟悉全拼的人可以很快入门。",-1),_=n("p",null,"双拼输入法也有很多种编码方案，如小鹤双拼、自然码双拼等，大家可根据喜好自行选择一种即可。本人使用的是小鹤双拼，其键位图如上图所示。",-1),m={href:"https://www.flypy.com/",target:"_blank",rel:"noopener noreferrer"},b=c(`<h1 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h1><p>windows系统也内置了双拼方案，但是没有小鹤双拼，下面介绍如何在windows中使用小鹤双拼。</p><ol><li>新建一个<code>小鹤双拼.reg</code>的注册表文件，内容如下：</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>Windows Registry Editor Version <span class="token number">5.00</span>

<span class="token punctuation">[</span>HKEY_CURRENT_USER<span class="token punctuation">\\</span>Software<span class="token punctuation">\\</span>Microsoft<span class="token punctuation">\\</span>InputMethod<span class="token punctuation">\\</span>Settings<span class="token punctuation">\\</span>CHS<span class="token punctuation">]</span>
<span class="token string">&quot;Enable Double Pinyin&quot;</span><span class="token operator">=</span>dword:00000001
<span class="token string">&quot;DoublePinyinScheme&quot;</span><span class="token operator">=</span>dword:0000000a
<span class="token string">&quot;Expand Double Pinyin&quot;</span><span class="token operator">=</span>dword:00000000
<span class="token string">&quot;UserDefinedDoublePinyinScheme0&quot;</span><span class="token operator">=</span><span class="token string">&quot;小鹤双拼*2*^*iuvdjhcwfg xmlnpbksqszxkrltvyovt&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>双击运行上面的<code>小鹤双拼.reg</code> (以管理员权限运行)</li></ol><h1 id="启用" tabindex="-1"><a class="header-anchor" href="#启用" aria-hidden="true">#</a> 启用</h1><p>可以在“设置”中查看和启用</p><figure><img src="https://blog.kevin2li.top/static/img/a25ec28b7b656eb562fe46ef58bf4abf.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure>`,8);function f(k,v){const a=r("ExternalLinkIcon");return t(),o("div",null,[d,u,g,h,_,n("p",null,[e("小鹤双拼官网："),n("a",m,[e("https://www.flypy.com/"),i(a)])]),l(" more "),b])}const x=s(p,[["render",f],["__file","Windows设置小鹤双拼输入法.html.vue"]]);export{x as default};
